const response = $input.first();
const prevData = $('Prepare Prompt').first().json;
// Em retry, Parse OK? já foi executado e carrega o retryCount incrementado
let retryCount = 0;
try {
  const parseOkOut = $('Parse OK?').first()?.json;
  if (parseOkOut?.retryCount) retryCount = parseOkOut.retryCount;
} catch(e) { /* primeiro run — Parse OK? ainda não executou */ }

const text = response.json.content?.[0]?.text;
if (!text) {
  if (retryCount >= 2) throw new Error('Claude não retornou conteúdo válido após 3 tentativas');
  return [{ json: { ...prevData, retryCount: retryCount + 1, status: 'parse_error', errorMsg: 'Sem conteúdo na resposta' } }];
}

const clean = text
  .replace(/```json\n?/g, '')
  .replace(/```\n?/g, '')
  .trim();

let script;
try {
  script = JSON.parse(clean);
} catch (e) {
  const match = clean.match(/\{[\s\S]*\}/);
  if (match) {
    try { script = JSON.parse(match[0]); } catch(e2) {}
  }
  if (!script) {
    if (retryCount >= 2) throw new Error('JSON inválido após 3 tentativas: ' + e.message);
    return [{ json: { ...prevData, retryCount: retryCount + 1, status: 'parse_error', errorMsg: e.message } }];
  }
}

if (!script.cenas || !Array.isArray(script.cenas)) {
  if (retryCount >= 2) throw new Error('Script sem cenas após 3 tentativas');
  return [{ json: { ...prevData, retryCount: retryCount + 1, status: 'parse_error', errorMsg: 'Script sem array de cenas' } }];
}

if (script.cenas.length < 4 || script.cenas.length > 6) {
  console.warn(`Aviso: ${script.cenas.length} cenas (esperado 4-6)`);
}

const duracaoTotal = script.cenas.reduce((sum, c) => sum + (c.duracao_segundos || 6), 0);

return [{
  json: {
    videoId: prevData.videoId,
    topicIndex: prevData.topicIndex,
    topic: prevData.topic,
    script,
    titulo: script.titulo,
    descricao: script.descricao,
    hashtags: script.hashtags,
    narracao: script.narracao_completa,
    cenas: script.cenas,
    duracao_total_segundos: duracaoTotal,
    status: 'script_ready'
  }
}];
